export const resolveWorkspaceSegmentVoiceoverPresentationDurationSeconds = (options: {
  isFinalSegment: boolean;
  voiceoverDurationSeconds: number | null | undefined;
}) => {
  const voiceoverDurationSeconds = normalizeWorkspaceSegmentManualDurationSeconds(
    options.voiceoverDurationSeconds,
  );
  if (voiceoverDurationSeconds === null) {
    return null;
  }

  return roundWorkspaceSegmentTimelineSeconds(
    voiceoverDurationSeconds +
      (options.isFinalSegment ? WORKSPACE_SEGMENT_FINAL_CLOSING_PADDING_SECONDS : 0),
  );
};

export const resolveWorkspaceSegmentDurationMenuTrimLabels = (options: {
  currentVideoDurationSeconds: number | null | undefined;
  locale: Parameters<typeof formatWorkspaceSegmentEditorSegmentDurationLabel>[2];
  voiceoverAudioDurationSeconds?: number | null;
  voiceoverDurationSeconds: number | null | undefined;
  voiceoverDurationSource?: "actual" | "estimated" | null;
}) => {
  const currentVideoDurationSeconds = normalizeWorkspaceSegmentManualDurationSeconds(
    options.currentVideoDurationSeconds,
  );
  const voiceoverDurationSeconds = normalizeWorkspaceSegmentManualDurationSeconds(options.voiceoverDurationSeconds);
  if (currentVideoDurationSeconds === null || voiceoverDurationSeconds === null) {
    return null;
  }

  const fullDurationLabel = formatWorkspaceSegmentEditorSegmentDurationLabel(
    0,
    currentVideoDurationSeconds,
    options.locale,
  ).replace(/\s+/g, "");
  const voiceoverDurationLabel = `${
    options.voiceoverDurationSource === "estimated" ? "≈" : ""
  }${formatWorkspaceSegmentEditorSegmentDurationLabel(
    0,
    voiceoverDurationSeconds,
    options.locale,
  ).replace(/\s+/g, "")}`;
  const voiceoverAudioDurationSeconds = normalizeWorkspaceSegmentManualDurationSeconds(
    options.voiceoverAudioDurationSeconds,
  );
  const voiceoverAudioDurationLabel = voiceoverAudioDurationSeconds !== null
    ? `${
        options.voiceoverDurationSource === "estimated" ? "≈" : ""
      }${formatWorkspaceSegmentEditorSegmentDurationLabel(
        0,
        voiceoverAudioDurationSeconds,
        options.locale,
      ).replace(/\s+/g, "")}`
    : null;
  const fullResultHoldsToVoiceover =
    voiceoverDurationSeconds > currentVideoDurationSeconds + WORKSPACE_SEGMENT_EXTENSION_EPSILON_SECONDS;

  return {
    fullDurationLabel,
    fullResultDurationLabel: fullResultHoldsToVoiceover ? voiceoverDurationLabel : fullDurationLabel,
    fullResultHoldsToVoiceover,
    ...(voiceoverAudioDurationLabel ? { voiceoverAudioDurationLabel } : {}),
    voiceoverDurationLabel,
  };
};

export const resolveWorkspaceSegmentVideoTrimDuration = (options: {
  requestedDurationSeconds: number | null | undefined;
  sourceVideoDurationSeconds: number | null | undefined;
  trimToVoiceover?: boolean | null;
  voiceoverDurationSeconds: number | null | undefined;
}) => {
  const sourceVideoDurationSeconds = normalizeWorkspaceSegmentManualDurationSeconds(options.sourceVideoDurationSeconds);
  const voiceoverDurationSeconds = normalizeWorkspaceSegmentManualDurationSeconds(options.voiceoverDurationSeconds);
  if (
    sourceVideoDurationSeconds === null ||
    voiceoverDurationSeconds === null ||
    sourceVideoDurationSeconds <= voiceoverDurationSeconds + WORKSPACE_SEGMENT_EXTENSION_EPSILON_SECONDS
  ) {
    return null;
  }

  const requestedDurationSeconds =
    options.trimToVoiceover === true
      ? voiceoverDurationSeconds
      : options.trimToVoiceover === false
        ? sourceVideoDurationSeconds
        : normalizeWorkspaceSegmentManualDurationSeconds(options.requestedDurationSeconds);
  if (requestedDurationSeconds === null) {
    return null;
  }

  return {
    durationSeconds: roundWorkspaceSegmentTimelineSeconds(
      Math.min(sourceVideoDurationSeconds, Math.max(voiceoverDurationSeconds, requestedDurationSeconds)),
    ),
    durationSyncMode: options.trimToVoiceover === true ? ("voiceover" as const) : ("visual" as const),
    maximumDurationSeconds: roundWorkspaceSegmentTimelineSeconds(sourceVideoDurationSeconds),
    minimumDurationSeconds: roundWorkspaceSegmentTimelineSeconds(voiceoverDurationSeconds),
  };
};

export const resolveWorkspaceSegmentTimelineVisualDurationDisplay = (options: {
  isImageDurationSegment: boolean;
  locale: Parameters<typeof formatWorkspaceSegmentEditorSegmentDurationLabel>[2];
  segmentSlotDurationSeconds: number;
  videoVisualDurationSeconds?: number | null;
}) => {
  const slotDurationSeconds = Number.isFinite(options.segmentSlotDurationSeconds)
    ? roundWorkspaceSegmentTimelineSeconds(Math.max(0, options.segmentSlotDurationSeconds))
    : 0;
  const visualDurationSeconds =
    !options.isImageDurationSegment &&
    typeof options.videoVisualDurationSeconds === "number" &&
    Number.isFinite(options.videoVisualDurationSeconds)
      ? roundWorkspaceSegmentTimelineSeconds(Math.max(0, options.videoVisualDurationSeconds))
      : slotDurationSeconds;

  return {
    badgeLabel: formatWorkspaceSegmentEditorDurationBadgeLabel(visualDurationSeconds, options.locale),
    durationLabel: formatWorkspaceSegmentEditorSegmentDurationLabel(0, visualDurationSeconds, options.locale),
  };
};

export const resolveWorkspaceSegmentDurationExtensionRequestTiming = (options: {
  requestedExtensionDurationSeconds: number | null | undefined;
  slotDurationSeconds: number | null | undefined;
  sourceDurationSeconds: number | null | undefined;
}) => {
  const sourceDurationSeconds = clampWorkspaceSegmentEditorVisualDurationSeconds(options.sourceDurationSeconds);
  const slotDurationSeconds = clampWorkspaceSegmentEditorVisualDurationSeconds(options.slotDurationSeconds);
  const requestedExtensionDurationSeconds = normalizeWorkspaceSegmentManualDurationSeconds(
    options.requestedExtensionDurationSeconds,
  );
  if (
    sourceDurationSeconds === null ||
    slotDurationSeconds === null ||
    requestedExtensionDurationSeconds === null ||
    slotDurationSeconds <= sourceDurationSeconds + WORKSPACE_SEGMENT_EXTENSION_EPSILON_SECONDS
  ) {
    return null;
  }

  const tailDurationSeconds = roundWorkspaceSegmentTimelineSeconds(
    Math.min(requestedExtensionDurationSeconds, slotDurationSeconds - sourceDurationSeconds),
  );
  const targetDurationSeconds = clampWorkspaceSegmentEditorVisualDurationSeconds(
    sourceDurationSeconds + tailDurationSeconds,
  );
  if (
    targetDurationSeconds === null ||
    tailDurationSeconds <= WORKSPACE_SEGMENT_EXTENSION_EPSILON_SECONDS ||
    targetDurationSeconds <= sourceDurationSeconds + WORKSPACE_SEGMENT_EXTENSION_EPSILON_SECONDS
  ) {
    return null;
  }

  return {
    sourceDurationSeconds,
    tailDurationSeconds,
    targetDurationSeconds,
  };
};

export const resolveWorkspaceSegmentSeedanceExtensionSelection = (options: {
  durationMode: StudioSegmentSeedanceDurationMode;
  manualDurationSeconds: unknown;
  voiceoverTailDurationSeconds?: number | null;
}) => {
  const voiceoverTailDurationSeconds = options.voiceoverTailDurationSeconds;
  const voiceoverMatched =
    typeof voiceoverTailDurationSeconds === "number" &&
    Number.isFinite(voiceoverTailDurationSeconds) &&
    voiceoverTailDurationSeconds <= WORKSPACE_SEGMENT_EXTENSION_EPSILON_SECONDS;
  const durationMode =
    options.durationMode === "voiceover" && voiceoverMatched ? "manual" : options.durationMode;

  return {
    durationMode,
    durationSeconds: resolveStudioSegmentSeedanceDurationSeconds({
      durationMode,
      manualDurationSeconds: options.manualDurationSeconds,
      voiceoverDurationSeconds: voiceoverTailDurationSeconds,
    }),
    voiceoverMatched,
  };
};

export const applyWorkspaceSegmentMeasuredSceneVoiceoverDuration = (
  segment: WorkspaceSegmentEditorDraftSegment,
  options: {
    durationSeconds: number | null | undefined;
    latestSceneVoiceoverAudioUrl?: string | null;
    speechStartTime: number;
  },
): WorkspaceSegmentEditorDraftSegment => {
  const nextDurationSeconds = normalizeWorkspaceSegmentManualDurationSeconds(options.durationSeconds);
  if (nextDurationSeconds === null) {
    return segment;
  }

  const durationSyncMode = normalizeWorkspaceSegmentDurationSyncMode(segment.durationSyncMode);
  const manualDurationSeconds = normalizeWorkspaceSegmentManualDurationSeconds(segment.manualDurationSeconds);
  const shouldPreserveUserSelectedVisualDuration =
    durationSyncMode === "visual" &&
    segment.durationSyncModeUserSelected === true &&
    normalizeWorkspaceSegmentDurationMode(segment.durationMode) === "manual" &&
    manualDurationSeconds !== null &&
    manualDurationSeconds + WORKSPACE_SEGMENT_EXTENSION_EPSILON_SECONDS >= nextDurationSeconds;
  const speechStartTime = roundWorkspaceSegmentTimelineSeconds(Math.max(0, options.speechStartTime));
  const speechEndTime = roundWorkspaceSegmentTimelineSeconds(speechStartTime + nextDurationSeconds);
  const visualStartTime = getWorkspaceSegmentEditorDisplayStartTime(segment);
  const nextVoiceoverAsset =
    options.latestSceneVoiceoverAudioUrl !== null && options.latestSceneVoiceoverAudioUrl !== undefined && segment.voiceoverAsset
      ? {
          ...segment.voiceoverAsset,
          durationSeconds: nextDurationSeconds,
        }
      : segment.voiceoverAsset;
  const timelinePatch: Partial<WorkspaceSegmentEditorDraftSegment> = shouldPreserveUserSelectedVisualDuration
    ? {}
    : {
        duration: nextDurationSeconds,
        durationExtensionSourceDurationSeconds: null,
        endTime: roundWorkspaceSegmentTimelineSeconds(visualStartTime + nextDurationSeconds),
        durationMode: "auto",
        durationSyncMode: "voiceover",
        durationSyncModeUserSelected:
          durationSyncMode === "voiceover" && segment.durationSyncModeUserSelected === true,
        manualDurationSeconds: null,
        startTime: visualStartTime,
      };

  return {
    ...segment,
    ...timelinePatch,
    speechDuration: nextDurationSeconds,
    speechDurationSource: "audio",
    speechEndTime,
    speechStartTime,
    voiceoverAsset: nextVoiceoverAsset,
  };
};

